# Generated by ollama (mistral)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
    agent {
        label 'master' // Runs on the master node
    }

    stages {
        stage('Build') {
            steps {
                // Your build commands here, e.g., maven, gradle, ant, etc.
                sh 'mvn clean install'
            }
        }

        stage('Test') {
            steps {
                // Your test commands here, e.g., mvn test, junit, testng, etc.
                sh 'mvn test'
            }
        }

        stage('Deploy') {
            when {
                branch 'master' // Only runs on the master branch by default
            }

            steps {
                // Your deployment commands here, e.g., scp, rsync, etc.
                sh 'rsync -avz target/your-artifact.jar user@remote:/path/to/deploy/'
            }
        }
    }
}